{"code": "import json

# Read list of all tables in stocktrade_database
file_path = locals()['var_functions.list_db:30']
with open(file_path, 'r') as f:
    all_tables = json.load(f)

# Read NYSE non-ETF stocks
info_file_path = locals()['var_functions.query_db:24']
with open(info_file_path, 'r') as f:
    nyse_stocks = json.load(f)

# Create set of NYSE symbols
nyse_symbols = {stock['Symbol'] for stock in nyse_stocks}

# Find intersection (stocks that exist in both databases)
available_stocks = []
for table in all_tables:
    if table in nyse_symbols:
        # Find the company name
        for stock in nyse_stocks:
            if stock['Symbol'] == table:
                available_stocks.append({
                    'Symbol': table,
                    'company_name': stock['company_name']
                })
                break

print('__RESULT__:')
print(json.dumps({
    "total_nyse_stocks": len(nyse_stocks),
    "total_tables": len(all_tables),
    "available_stocks": len(available_stocks),
    "sample_available": [s['Symbol'] for s in available_stocks[:10]]
}))"}

